import { useEvent } from "../../../../hooks/use-event.js";
export function useEditUpdateCells(props, api, source, view) {
    return useEvent((updates) => {
        const updateMap = new Map();
        updates.forEach((updates, key) => {
            const row = typeof key === "number" ? source.rowByIndex(key).get() : source.rowById(key);
            if (!row)
                return;
            let nextData = structuredClone(row.data);
            for (const { column: c, value } of updates) {
                let column;
                if (typeof c === "string")
                    column = view.lookup.get(c);
                else if (typeof c === "number")
                    column = view.visibleColumns.at(c);
                else
                    column = view.lookup.get(c.id);
                if (!column)
                    continue;
                const setter = (column ?? props.columnBase)?.editSetter;
                if (setter) {
                    nextData = setter({ api, column, editData: nextData, editValue: value, row });
                }
                else {
                    const field = (column.field ?? column.id);
                    if (typeof field !== "number" && typeof field !== "string")
                        return false;
                    nextData[field] = value;
                }
            }
            updateMap.set(key, nextData);
        });
        return api.editUpdateRows(updateMap);
    });
}
