import { useMemo } from "react";
import { usePiece } from "../hooks/use-piece.js";
export function useRows(flatten) {
    const rows = useMemo(() => {
        return {
            get: (i) => flatten[i],
            size: flatten.length,
        };
    }, [flatten]);
    const rows$ = usePiece(rows);
    return rows$;
}
