import { getCell, getGridId, getHeaderCell, getHeaderFloating, getHeaderGroup, getRow, getRowDetail, getRowType, getViewport, } from "./attributes.js";
export const isHeaderGroup = (gridId, el) => getHeaderGroup(el) === "true" && getGridId(el) === gridId;
export const isHeaderCell = (gridId, el) => getHeaderCell(el) === "true" && getGridId(el) === gridId && getHeaderFloating(el) == null;
export const isFloatingCell = (gridId, el) => getHeaderCell(el) === "true" && getGridId(el) === gridId && getHeaderFloating(el) == "true";
export const isCell = (gridId, el) => getCell(el) === "true" && getGridId(el) === gridId;
export const isFullWidth = (gridId, el) => getRow(el) === "true" && getRowType(el) === "full-width" && getGridId(el) === gridId;
export const isDetail = (gridId, el) => getRowDetail(el) === "true" && getGridId(el) === gridId;
export const isViewport = (gridId, el) => getViewport(el) === "true" && getGridId(el) === gridId;
export const isRow = (gridId, el) => el.getAttribute("data-ln-row") === "true" && el.getAttribute("data-ln-gridid") === gridId;
