import { useMemo, useRef } from "react";
const leafIdFallback = (_, i, s) => (s !== "center" ? `leaf-${i}-${s}` : `leaf-${i}`);
export function useLeafNodes(top, center, bot, leafIdFn) {
    const nodeCache = useRef(new Map());
    const leafsCenter = useMemo(() => {
        const nextMap = new Map();
        const nextNodes = [];
        const lookup = nodeCache.current;
        for (let i = 0; i < center.length; i++) {
            const d = center[i];
            const idFn = leafIdFn ?? leafIdFallback;
            const node = lookup.get(d) ?? makeLeafNode(d, i, "center");
            node.__srcIndex = i;
            node.id = idFn(d, i, "center");
            nextMap.set(d, node);
            nextNodes.push(node);
        }
        nodeCache.current = nextMap;
        return nextNodes;
    }, [center, leafIdFn]);
    const [leafsTop, topMap] = useMemo(() => {
        const idMap = new Map();
        if (!top)
            return [[], idMap];
        const topNodes = top.map((x, i) => {
            const node = makeLeafNode(x, i, "top");
            const idFn = leafIdFn ?? leafIdFallback;
            node.__srcIndex = i;
            node.id = idFn(x, i, "top");
            idMap.set(node.id, node);
            return node;
        });
        return [topNodes, idMap];
    }, [leafIdFn, top]);
    const [leafsBot, botMap] = useMemo(() => {
        const idMap = new Map();
        if (!bot)
            return [[], idMap];
        const botNodes = bot.map((x, i) => {
            const idFn = leafIdFn ?? leafIdFallback;
            const node = makeLeafNode(x, i, "bottom");
            node.__srcIndex = i;
            node.id = idFn(x, i, "top");
            return node;
        });
        return [botNodes, idMap];
    }, [bot, leafIdFn]);
    const pinMap = useMemo(() => {
        return new Map([...topMap, ...botMap]);
    }, [botMap, topMap]);
    return [leafsTop, leafsCenter, leafsBot, pinMap];
}
const makeLeafNode = (d, i, section) => ({
    kind: "leaf",
    data: d,
    depth: 0,
    id: "",
    __pin: section,
    __srcIndex: i,
});
