import { useEvent } from "../hooks/use-event.js";
export function useRowById(tree, leafIdsRef) {
    const rowById = useEvent((id) => {
        if (!tree)
            return leafIdsRef.current.get(id) ?? null;
        const node = tree.groupLookup.get(id)?.row ?? leafIdsRef.current.get(id) ?? null;
        return node;
    });
    return rowById;
}
