import { useMemo } from "react";
export function useFlattenedGroups(root, agg, leafs, workingSet, sort, expandedFn) {
    const flat = useMemo(() => {
        if (!root)
            return [null, 0];
        const flatList = [];
        const ranges = [];
        let maxDepth = 0;
        function processRowsBetter(node, parent, start, isLast, depth = 0) {
            maxDepth = Math.max(depth + 1, maxDepth);
            const rows = nodeChildrenToRows(node, agg, leafs, workingSet, sort, isLast);
            let offset = 0;
            for (let i = 0; i < rows.length; i++) {
                const row = rows[i];
                const rowIndex = i + start + offset;
                if (row.kind === "leaf") {
                    flatList.push(row);
                    continue;
                }
                flatList.push(row);
                if (!expandedFn(row.id, depth)) {
                    row.expanded = false;
                    continue;
                }
                row.expanded = true;
                offset += processRowsBetter(row.__children, row, rowIndex + 1, row.last, depth + 1);
            }
            ranges.push({ parent, start, end: offset + start + node.size });
            return offset + node.size;
        }
        const count = processRowsBetter(root.children, null, 0, root.maxDepth <= 1);
        // Potentially do something with these??
        void ranges;
        void count;
        return [flatList, maxDepth];
    }, [agg, expandedFn, leafs, root, sort, workingSet]);
    return flat;
}
const nodeChildrenToRows = (root, agg, leafs, workingSet, sort, isLast) => {
    const values = root.values();
    const rows = [];
    for (const v of values) {
        if (v.kind === "leaf") {
            rows.push(v.row);
            continue;
        }
        else {
            const data = agg ? agg(v.leafs.map((i) => leafs[workingSet[i]])) : {};
            const row = v.row;
            row.data = data;
            rows.push(row);
        }
    }
    if (!isLast && sort)
        return rows.sort(sort);
    return rows;
};
