// https://github.com/oleggrishechkin/react-tagged-state
import { useMemo, useSyncExternalStore } from "react";
const EMPTY = {};
let clock = {};
export const createEvent = () => {
    let callbacks = null;
    return Object.assign((value) => {
        if (callbacks) {
            for (const callback of callbacks) {
                callback(value);
            }
        }
    }, {
        on: (callback) => {
            if (!callbacks) {
                callbacks = new Set();
            }
            callbacks.add(callback);
            return () => {
                if (callbacks) {
                    callbacks.delete(callback);
                    if (!callbacks.size) {
                        callbacks = null;
                    }
                }
            };
        },
    });
};
const clockUpdateEvent = createEvent();
export const createSignal = (initialValue) => {
    const event = createEvent();
    let value = initialValue;
    return Object.assign((...args) => {
        if (args.length) {
            const nextValue = args[0];
            if (nextValue !== value) {
                value = nextValue;
                event(value);
                clock = {};
                clockUpdateEvent();
            }
        }
        return value;
    }, { on: event.on });
};
export const useSelector = (signal, selector) => {
    const snapshot = useMemo(() => {
        if ("on" in signal) {
            if (selector) {
                let lastSignalValue = EMPTY;
                let value;
                return () => {
                    const nextSignalValue = signal();
                    if (nextSignalValue !== lastSignalValue) {
                        lastSignalValue = nextSignalValue;
                        value = selector(nextSignalValue);
                    }
                    return value;
                };
            }
            return signal;
        }
        let lastClock = EMPTY;
        let value;
        return () => {
            if (clock !== lastClock) {
                lastClock = clock;
                value = signal();
            }
            return value;
        };
    }, [selector, signal]);
    return useSyncExternalStore("on" in signal ? signal.on : clockUpdateEvent.on, snapshot, snapshot);
};
