import { equal } from "@1771technologies/js-utils";
import { cellEqual } from "./cell-equal.js";
export function positionsEqual(p, c) {
    if ((p?.kind === "cell" && c?.kind === "cell" && cellEqual(p, c)) || equal(p, c))
        return true;
    if (p?.kind === "full-width" && c?.kind === "full-width" && c.rowIndex === p.rowIndex)
        return true;
    if (p?.kind === "detail" && c?.kind === "detail" && c.rowIndex === p.rowIndex)
        return true;
    return equal(p, c);
}
