import { useEvent } from "../hooks/use-event.js";
export function useRowDelete(props, rowById) {
    const rowDelete = useEvent((rows) => {
        const finalRows = [];
        const indices = [];
        for (let i = 0; i < rows.length; i++) {
            const row = rowById(rows[i].id);
            if (!row) {
                console.error(`The row with id ${rows[i]?.id} does not exist in the data source.`);
                return;
            }
            if (row.kind !== "leaf") {
                console.error(`Only leaf rows may be deleted from the client data source. Non-leaf row provided`, row);
                return;
            }
            finalRows.push(row);
            indices.push(row.__srcIndex);
        }
        props.onRowsDeleted?.({
            rows: finalRows,
            sourceIndices: indices,
            top: props.topData ?? [],
            center: props.data ?? [],
            bottom: props.bottomData ?? [],
        });
    });
    return rowDelete;
}
