import { columnPositions } from "@1771technologies/lytenyte-shared";
import { useMemo } from "react";
export function useXPositions(props, view, containerWidth) {
    const xLayout = useMemo(() => {
        const columns = view.visibleColumns;
        const next = columnPositions(columns, props.columnBase ?? {}, containerWidth, props.columnSizeToFit ?? false);
        return next;
    }, [containerWidth, props.columnBase, props.columnSizeToFit, view.visibleColumns]);
    return xLayout;
}
