export function getSpanFn(rowByIndex, visibleColumns, span, api) {
    if (visibleColumns.every((c) => !(span === "col" ? c.colSpan : c.rowSpan)))
        return null;
    return (r, c) => {
        const row = rowByIndex(r);
        const column = visibleColumns[c];
        if (!row || !column)
            return 1;
        const spanFn = span === "col" ? column.colSpan : column.rowSpan;
        if (!spanFn)
            return 1;
        if (typeof spanFn === "number") {
            if (span === "col") {
                return spanFn;
            }
            else {
                return r % spanFn === 0 ? spanFn : 1;
            }
        }
        return spanFn({ rowIndex: r, colIndex: c, column: column, row, api });
    };
}
