import { getWindow } from "@1771technologies/dom-utils";
import { nearestFocusable } from "./nearest-focusable.js";
import { positionFromElement } from "./position-from-element.js";
import { positionsEqual } from "./positions-equal.js";
export function trackFocus({ gridId, focusActive, onHasFocusChange, onElementFocused, element, }) {
    const controller = new AbortController();
    const onFocusChange = (p) => {
        const c = focusActive.get();
        if (positionsEqual(p, c))
            return;
        focusActive.set(p);
    };
    element.addEventListener("focusin", (ev) => {
        onHasFocusChange(true);
        const el = nearestFocusable(gridId, ev.target);
        if (!el) {
            onHasFocusChange(false);
            onFocusChange(null);
            return;
        }
        const position = positionFromElement(gridId, el);
        onFocusChange(position);
    }, { signal: controller.signal });
    element.addEventListener("focusout", (ev) => {
        if (!getWindow(element).document.hasFocus())
            return;
        if (ev.relatedTarget && element.contains(ev.relatedTarget))
            return;
        onHasFocusChange(false);
        onFocusChange(null);
    }, { signal: controller.signal });
    element.addEventListener("focus", () => onElementFocused(true), { signal: controller.signal });
    element.addEventListener("blur", () => onElementFocused(false), { signal: controller.signal });
    return () => {
        controller.abort();
    };
}
