import { useEvent } from "../hooks/use-event.js";
export function useRowSiblings(tree) {
    const rowSiblings = useEvent((id) => {
        const group = tree?.groupLookup.get(id);
        const parent = group?.parent;
        if (!parent)
            return [];
        return [
            ...parent.children
                .values()
                .map((x) => (x.kind === "branch" ? x.row.id : null))
                .filter(Boolean),
        ];
    });
    return rowSiblings;
}
