import { useEvent } from "../../../../hooks/use-event.js";
export function useRowDetailHeight(rowDetailHeight, rowDetailAutoHeightGuess, detailExpansions, detailHeightCache) {
    return useEvent((rowOrId) => {
        const id = typeof rowOrId === "string" ? rowOrId : rowOrId.id;
        if (!detailExpansions.has(id))
            return 0;
        if (rowDetailHeight === "auto")
            return detailHeightCache[id] ?? rowDetailAutoHeightGuess ?? 200;
        return rowDetailHeight ?? 200;
    });
}
