import { useMemo } from "react";
import { computeField } from "../root/hooks/use-api/auxiliary-functions/compute-field.js";
export function useGroupFn(group) {
    return useMemo(() => {
        if (!group)
            return null;
        if (!Array.isArray(group))
            return group;
        const fn = (row) => {
            return group.map((x) => {
                const field = x.field ?? x.id;
                return computeField(field, row);
            });
        };
        return fn;
    }, [group]);
}
