import { isDocument, isHTMLElement, isShadowRoot } from "../predicates/index.js";
/** Returns the window associated with the given node, document, or shadow root. */
export function getWindow(el) {
    if (isShadowRoot(el))
        return getWindow(el.host);
    if (isDocument(el))
        return el.defaultView ?? window;
    if (isHTMLElement(el))
        return el.ownerDocument?.defaultView ?? window;
    return window;
}
