import { isRow, isViewport } from "./predicates.js";
export function getNearestRow(gridId, el) {
    if (!el)
        el = document.activeElement;
    if (!el)
        return null;
    let current = el;
    while (current && !isViewport(gridId, current)) {
        if (isRow(gridId, current)) {
            return current;
        }
        current = current.parentElement;
    }
    return null;
}
